solution_code:
#include <iostream>

int square(int n)
{
    int result = n * n;
    std::cerr << "[square] n=" << n << " result=" << result << '\n';
    return result;
}

int addOffset(int value, int offset)
{
    int result = value + offset;
    std::cerr << "[addOffset] value=" << value << " offset=" << offset << " result=" << result << '\n';
    return result;
}

int main()
{
    int n = 0;
    int offset = 0;
    std::cin >> n >> offset;
    std::cout << "Result: " << addOffset(square(n), offset) << '\n';
    return 0;
}

