#include <iostream>

int multiplyTwo(int a, int b)
{
    std::cerr << "[multiplyTwo] a=" << a << " b=" << b << '\n';
    return a * b;
}

int addTen(int x)
{
    std::cerr << "[addTen] x=" << x << '\n';
    return x + 10;
}

int main()
{
    int a = 0;
    int b = 0;
    std::cin >> a >> b;
    std::cout << "Answer: " << addTen(multiplyTwo(a, b)) << '\n';
    return 0;
}
